solution_code:
#include <iostream>
#include <string>
#include <vector>

class Animal
{
public:
    virtual std::string describe() const { return "Animal: ..."; }
};

class Cat : public Animal
{
public:
    std::string describe() const override { return "Cat: Meow"; }
};

class Dog : public Animal
{
public:
    std::string describe() const override { return "Dog: Woof"; }
};

class Cow : public Animal
{
public:
    std::string describe() const override { return "Cow: Moo"; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Animal*> animals{};
    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "cat")
            animals.push_back(new Cat{});
        else if (type == "dog")
            animals.push_back(new Dog{});
        else if (type == "cow")
            animals.push_back(new Cow{});
        else
            animals.push_back(new Animal{});
    }

    for (const Animal* a : animals)
        std::cout << a->describe() << '\n';

    for (Animal* a : animals)
        delete a;

    return 0;
}

